// Este código simula o Structured Output Parser do n8n
// Ele converte o texto retornado pelo LLM em objetos JSON válidos

for (const item of $input.all()) {
  let raw = item.json.text || "";
  let parsed = [];

  try {
    // Tenta identificar e limpar o conteúdo JSON dentro do texto
    raw = raw
      .replace(/```json/g, "")
      .replace(/```/g, "")
      .trim();

    // Se o texto começar com [, tenta parsear como array
    if (raw.startsWith("[")) {
      parsed = JSON.parse(raw);
    } else if (raw.startsWith("{")) {
      // Se for um único objeto
      parsed = [JSON.parse(raw)];
    } else {
      // Caso o modelo tenha retornado algo como "json:\n[...]"
      const match = raw.match(/\[([\s\S]*)\]/);
      if (match) parsed = JSON.parse("[" + match[1] + "]");
    }

  } catch (error) {
    // Se der erro de parse, mostra no console (para debug)
    console.log("Erro ao converter JSON:", error.message);
    parsed = [{ ordem: 0, texto: raw }];
  }

  // Retorna cada bloco como item separado
  return parsed.map((b, index) => ({
    json: {
      ordem: b.ordem ?? index,
      texto: b.texto ?? "",
    },
  }));
}
